def is_luhn_valid(card_number_str: str) -> bool:
    cleaned_card_number = ''.join(filter(str.isdigit, card_number_str))

    if not cleaned_card_number:
        return False

    digits = [int(d) for d in cleaned_card_number]

    total_sum = 0

    for i, digit in enumerate(reversed(digits)):
        if i % 2 == 1:
            doubled_digit = digit * 2
            if doubled_digit > 9:
                total_sum += (doubled_digit - 9)
            else:
                total_sum += doubled_digit
        else:
            total_sum += digit

    return total_sum % 10 == 0
